import React, { useState, useEffect, useRef } from "react";
import axios from "axios";
import Cookies from "js-cookie";
import { useNavigate } from "react-router-dom";
import { Modal } from "bootstrap";
import { toast } from "react-toastify";
import Toast from "../components/Toast";
import copy from "copy-to-clipboard";

const API_BASE_URL =
  process.env.REACT_APP_API_BASE_URL || "http://localhost:5000/api";

function PaymentsManagement() {
  const [payments, setPayments] = useState([]);
  const [loading, setLoading] = useState(false);

  const [formData, setFormData] = useState({
    id: null,
    paymentMethod: "",
    totalAmount: "",
    paidAmount: "",
    remainingAmount: "",
    isPartial: false,
    status: "",
    transactionId: "",
  });

  const [filters, setFilters] = useState({
    search: "",
    status: "",
  });

  const [currentPage, setCurrentPage] = useState(1);
  const paymentsPerPage = 10;

  const modalRef = useRef(null);
  const navigate = useNavigate();

  /* ================= FETCH PAYMENTS ================= */
  function fetchPayments() {
    setLoading(true);
    const token = Cookies.get("adminToken");

    axios
      .get(API_BASE_URL + "/payments", {
        headers: { Authorization: "Bearer " + token },
      })
      .then((response) => {
        if (response.data.success) {
          setPayments(response.data.data);
        } else {
          toast.error("Failed to fetch payments");
        }
      })
      .catch((err) => {
        toast.error(err.response?.data?.error || "Error fetching payments");
      })
      .finally(() => {
        setLoading(false);
      });
  }

  useEffect(() => {
    const token = Cookies.get("adminToken");
    if (!token) {
      navigate("/");
    } else {
      fetchPayments();
    }
  }, [navigate]);

  /* ================= INPUT CHANGE ================= */
  function handleInputChange(e) {
    const { name, value } = e.target;

    let updated = { ...formData, [name]: value };

    // Auto calculate remaining
    if (name === "paidAmount" || name === "totalAmount") {
      const total =
        parseFloat(name === "totalAmount" ? value : updated.totalAmount) || 0;
      const paid =
        parseFloat(name === "paidAmount" ? value : updated.paidAmount) || 0;

      updated.remainingAmount = total - paid;
      updated.isPartial = paid < total;
    }

    setFormData(updated);
  }

  /* ================= FILTER CHANGE ================= */
  function handleFilterChange(e) {
    const { name, value } = e.target;
    setFilters((prev) => ({ ...prev, [name]: value }));
    setCurrentPage(1);
  }

  /* ================= EDIT ================= */
  function handleEdit(payment) {
    setFormData({
      id: payment.id,
      paymentMethod: payment.paymentMethod,
      totalAmount: payment.totalAmount,
      paidAmount: payment.paidAmount,
      remainingAmount: payment.remainingAmount,
      isPartial: payment.isPartial,
      status: payment.status,
      transactionId: payment.transactionId,
    });

    const modalEl = document.getElementById("editPaymentModal");
    modalRef.current = new Modal(modalEl);
    modalRef.current.show();
  }

  /* ================= UPDATE ================= */
  function handleSubmit(e) {
    e.preventDefault();
    const token = Cookies.get("adminToken");

    axios
      .put(API_BASE_URL + "/payments/" + formData.id, formData, {
        headers: { Authorization: "Bearer " + token },
      })
      .then(() => {
        toast.success("Payment updated successfully");
        fetchPayments();
        modalRef.current.hide();
      })
      .catch((err) => {
        toast.error(err.response?.data?.error || "Update failed");
      });
  }

  /* ================= DELETE ================= */
  function handleDelete(id) {
    if (!window.confirm("Delete this payment?")) return;

    const token = Cookies.get("adminToken");

    axios
      .delete(API_BASE_URL + "/payments/" + id, {
        headers: { Authorization: "Bearer " + token },
      })
      .then(() => {
        toast.success("Payment deleted successfully");
        fetchPayments();
      })
      .catch((err) => {
        toast.error(err.response?.data?.error || "Delete failed");
      });
  }

  /* ================= FILTERED PAYMENTS ================= */
  const filteredPayments = payments.filter((p) => {
    const searchMatch = filters.search
      ? ((p.userName || "") + (p.transactionId || ""))
          .toLowerCase()
          .includes(filters.search.toLowerCase())
      : true;

    const statusMatch = filters.status ? p.status === filters.status : true;

    return searchMatch && statusMatch;
  });

  /* ================= PAGINATION ================= */
  const indexOfLast = currentPage * paymentsPerPage;
  const indexOfFirst = indexOfLast - paymentsPerPage;
  const currentPayments = filteredPayments.slice(indexOfFirst, indexOfLast);
  const totalPages = Math.ceil(filteredPayments.length / paymentsPerPage);

  function goToNextPage() {
    if (currentPage < totalPages) setCurrentPage((prev) => prev + 1);
  }

  function goToPreviousPage() {
    if (currentPage > 1) setCurrentPage((prev) => prev - 1);
  }

  /* ================= COPY ================= */
  function handleCopy(text) {
    if (copy(text)) toast.success("Copied to clipboard");
    else toast.error("Copy failed");
  }

  /* ================= User Details ================= */
const [userDetails, setUserDetails] = useState(null);
const userModalRef = useRef(null);

function openUserModal(user) {
  if (!user.userId) return;

  setUserDetails(user);

  const modalEl = document.getElementById("userModal");
  userModalRef.current = new Modal(modalEl);
  userModalRef.current.show();
}


  /* ================= UI ================= */
  return (
    <div className="container mt-3">
      <Toast />

      <div className="row mb-3">
        <div className="col">
          <i
            className="fa fa-arrow-left mt-2"
            style={{ cursor: "pointer" }}
            onClick={() => navigate("/dashboard")}
          ></i>
        </div>
      </div>

      <h4 className="fw-bold mb-3">Payments Management</h4>

      {/* FILTERS */}
      <div className="row g-3 mb-3">
        <div className="col-md-6">
          <input
            type="text"
            name="search"
            className="form-control form-control-sm"
            placeholder="Search User / Transaction ID"
            value={filters.search}
            onChange={handleFilterChange}
          />
        </div>

        <div className="col-md-6">
          <select
            name="status"
            className="form-select form-select-sm"
            value={filters.status}
            onChange={handleFilterChange}
          >
            <option value="">Status</option>
            <option value="Pending">Pending</option>
            <option value="Success">Success</option>
            <option value="Rejected">Rejected</option>
          </select>
        </div>
      </div>

      {/* ================= APPLIED FILTERS ================= */}
      {(filters.search || filters.status) && (
        <div className="row g-3 mb-3">
          <div className="col-auto">
            <span className="fw-semibold">Filters applied:</span>
          </div>

          {filters.search && (
            <div className="col-auto">
              <span className="badge bg-secondary">
                Search: {filters.search}{" "}
                <i
                  className="fa fa-times ms-1"
                  style={{ cursor: "pointer" }}
                  onClick={() =>
                    setFilters((prev) => ({ ...prev, search: "" }))
                  }
                ></i>
              </span>
            </div>
          )}

          {filters.status && (
            <div className="col-auto">
              <span className="badge bg-secondary">
                Status: {filters.status}{" "}
                <i
                  className="fa fa-times ms-1"
                  style={{ cursor: "pointer" }}
                  onClick={() =>
                    setFilters((prev) => ({ ...prev, status: "" }))
                  }
                ></i>
              </span>
            </div>
          )}
        </div>
      )}

      <div className="card border-0 mb-3">
        {loading ? (
          <div className="text-center">Loading...</div>
        ) : (
          <div className="table-responsive rounded">
            <table className="table table-striped table-hover mb-0 small">
              <thead className="table-dark">
                <tr>
                  <th>ID</th>
                  <th>User</th>
                  <th>Method</th>
                  <th>Total</th>
                  <th>Paid</th>
                  <th>Remaining</th>
                  <th>Status</th>
                  <th>Transaction</th>
                  <th>Date</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {currentPayments.map((p) => (
                  <tr key={p.id}>
                    <td>{p.id}</td>
                    <td>
  <i
    className="fa-solid fa-user text-info"
    style={{ cursor: "pointer" }}
    onClick={() => openUserModal(p)}
    title="View User Details"
  ></i>
</td>

                    <td>{p.paymentMethod}</td>
                    <td>{p.totalAmount}</td>
                    <td>{p.paidAmount}</td>
                    <td>{p.remainingAmount}</td>
                    <td>{p.status}</td>
                    <td>
                      {p.transactionId}
                      <i
                        className="fa-solid fa-copy ms-2 text-primary"
                        style={{ cursor: "pointer" }}
                        onClick={() => handleCopy(p.transactionId)}
                      ></i>
                    </td>
                    <td>{new Date(p.paymentDate).toLocaleString()}</td>
                    <td>
                      <i
                        className="fa-solid fa-pen-to-square text-primary me-3"
                        style={{ cursor: "pointer" }}
                        onClick={() => handleEdit(p)}
                      ></i>
                      <i
                        className="fa-solid fa-trash text-danger"
                        style={{ cursor: "pointer" }}
                        onClick={() => handleDelete(p.id)}
                      ></i>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {/* PAGINATION */}
      <div className="d-flex justify-content-between align-items-center mb-3">
        <div>
          Page {currentPage} of {totalPages} • {filteredPayments.length} records
        </div>
        <div>
          <button
            className="btn btn-sm border-0"
            onClick={goToPreviousPage}
            disabled={currentPage === 1}
          >
            <i className="fa-solid fa-chevron-left"></i>
          </button>
          <button
            className="btn btn-sm border-0"
            onClick={goToNextPage}
            disabled={currentPage === totalPages || totalPages === 0}
          >
            <i className="fa-solid fa-chevron-right"></i>
          </button>
        </div>
      </div>

      {/* EDIT MODAL */}
      <div className="modal fade" id="editPaymentModal">
        <div className="modal-dialog modal-dialog-centered">
          <div className="modal-content">
            <form onSubmit={handleSubmit}>
              <div className="modal-header">
                <h5 className="modal-title">Edit Payment</h5>
                <button
                  type="button"
                  className="btn-close"
                  data-bs-dismiss="modal"
                ></button>
              </div>

              <div className="modal-body">
                <div className="mb-3">
                  <label>Method</label>
                  <input
                    type="text"
                    name="paymentMethod"
                    className="form-control"
                    placeholder="Payment Method"
                    value={formData.paymentMethod}
                    onChange={handleInputChange}
                  />
                </div>

                <div className="mb-3">
                  <label>Total Amount</label>
                  <input
                    type="number"
                    name="totalAmount"
                    className="form-control"
                    placeholder="Total Amount"
                    value={formData.totalAmount}
                    onChange={handleInputChange}
                  />
                </div>

                <div className="mb-3">
                  <label>Paid Amount</label>
                  <input
                    type="number"
                    name="paidAmount"
                    className="form-control mb-2"
                    placeholder="Paid Amount"
                    value={formData.paidAmount}
                    onChange={handleInputChange}
                  />
                </div>

                <div className="mb-3">
                  <label>Remaining Amount</label>
                  <input
                    type="number"
                    name="remainingAmount"
                    className="form-control mb-2"
                    placeholder="Remaining"
                    value={formData.remainingAmount}
                    readOnly
                  />
                </div>

                <div className="mb-3">
                  <label>Status</label>
                  <select
                    name="status"
                    className="form-select mb-2"
                    value={formData.status}
                    onChange={handleInputChange}
                  >
                    <option value="Pending">Pending</option>
                    <option value="Success">Success</option>
                    <option value="Rejected">Rejected</option>
                  </select>
                </div>

                <div className="mb-3">
                  <label>Transaction ID</label>
                  <input
                    type="text"
                    name="transactionId"
                    className="form-control"
                    placeholder="Transaction ID"
                    value={formData.transactionId}
                    onChange={handleInputChange}
                  />
                </div>
              </div>

              <div className="modal-footer">
                <button type="submit" className="btn btn-primary">
                  Update
                </button>
              </div>
            </form>
          </div>
        </div>
      </div>

      {/* ================= User Details Modal ================= */}
<div className="modal fade" id="userModal" tabIndex="-1">
  <div className="modal-dialog modal-dialog-centered">
    <div className="modal-content">
      <div className="modal-header">
        <h5 className="modal-title">User Details</h5>
        <button
          type="button"
          className="btn-close"
          data-bs-dismiss="modal"
        ></button>
      </div>
      <div className="modal-body">
        {userDetails ? (
          <div>
            <p>
              <strong>ID:</strong> {userDetails.userId}
              <i
                className="fa-solid fa-copy ms-2"
                style={{ cursor: "pointer" }}
                onClick={() => handleCopy(userDetails.userId, "User ID")}
              ></i>
            </p>
            <p>
              <strong>Name:</strong> {userDetails.userName}
              <i
                className="fa-solid fa-copy ms-2"
                style={{ cursor: "pointer" }}
                onClick={() => handleCopy(userDetails.userName, "User Name")}
              ></i>
            </p>
            <p>
              <strong>Phone:</strong> {userDetails.userPhone}
              <i
                className="fa-solid fa-copy ms-2"
                style={{ cursor: "pointer" }}
                onClick={() =>
                  handleCopy(userDetails.userPhone, "User Phone")
                }
              ></i>
            </p>
            <p>
              <strong>Email:</strong> {userDetails.userEmail}
              <i
                className="fa-solid fa-copy ms-2"
                style={{ cursor: "pointer" }}
                onClick={() =>
                  handleCopy(userDetails.userEmail, "User Email")
                }
              ></i>
            </p>
          </div>
        ) : (
          <p>No user assigned</p>
        )}
      </div>
    </div>
  </div>
</div>

    </div>
  );
}

export default PaymentsManagement;
